import org.springframework.stereotype.Controller;
import org.springframework.web.bind.annotation.GetMapping;

@Controller
public class LogoutController {
    
    @GetMapping("/logout")
    public String logout(HttpServletRequest request, HttpServletResponse response) throws IOException {
        if (request.getParameter("next") != null && (!request.isSecure() || ("http".equalsIgnoreCase(request.getScheme()) && 80 == request.getServerPort()))){ // If the "next" parameter is set and it's a secure connection or port 443 (HTTPS)
            response.sendRedirect("https://www.yourwebsiteurl/" + UriComponentsBuilder.fromUri(request.getParameter("next")).build());// Redirection to the "next" URL after logout, appending necessary query parameters if any exists in next url 
        } else { // If not secure or port is different from default (HTTPS) then just redirect back with no additional information like using response.sendRedirect(requestURI); without parameter  
            return "redirect:/";// Redirection to root page after logout, use "/" instead of "" if you want the app indexpage 
        }      
    }        
}